```bash
sed -i '1483,1490c\  if (IsAnd && stripSignOnlyFPOps(LHS0) == stripSignOnlyFPOps(RHS0)) {
    // Avoid dropping poison-masking when used in a logical select and the RHS/LHS
    // involves fabs that may produce poison (e.g., has no "no-nans" FMF).
    auto IsUnsafeFabs = [](Value *V) {
      if (auto *CI = dyn_cast<CallInst>(V))
        if (CI->getIntrinsicID() == Intrinsic::fabs && !CI->hasNoNaNs())
          return true;
      return false;
    };
    if (!(IsLogicalSelect && (IsUnsafeFabs(RHS0) || IsUnsafeFabs(LHS0)))) {
      // and (fcmp ord x, 0), (fcmp u* x, inf) -> fcmp o* x, inf
      // and (fcmp ord x, 0), (fcmp u* fabs(x), inf) -> fcmp o* x, inf
      if (Value *Left = matchIsFiniteTest(Builder, LHS, RHS))
        return Left;
      if (Value *Right = matchIsFiniteTest(Builder, RHS, LHS))
        return Right;
    }
  }' llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp && submit-patch
