  // This preserves poison-masking via the select for nnan fabs on sNaN inputs.
  if (I.hasOneUse()) {
    if (auto *SI = dyn_cast<SelectInst>(I.user_back())) {
      if (auto *CI = dyn_cast<CallInst>(Op0)) {
        if (CI->getIntrinsicID() == Intrinsic::fabs && !CI->hasNoNaNs()) {
          return nullptr;
